ALTER TABLE public.email_teachings DROP CONSTRAINT IF EXISTS email_teachings_theme_check;
ALTER TABLE public.email_teachings ADD CONSTRAINT email_teachings_theme_check CHECK (theme IN (
  'abundance','ayurveda','jyotish','mantra_practice',
  'bhakti_devotion','protection','pranayama','general',
  'mudra','sacred_geometry','kriya_yoga','water_alchemy','brahmacharya',
  'longevity','mediumship'
));

